1	---
2	component: TreeView
3	category: navigation
4	tier: complex
5	foundation_deps: [architecture, accessibility, interactions, collections]
6	shared_deps: []
7	related: []
8	references:
9	    ark-ui: TreeView
10	    react-aria: Tree
11	---
12	
13	# TreeView
14	
15	A hierarchical, keyboard-navigable tree with expand/collapse and optional node selection.
16	Implements the ARIA tree widget pattern with `role="tree"`, `role="treeitem"`, and
17	`role="group"` for nested subtrees.
18	
19	## 1. State Machine
20	
21	### 1.1 States
22	
23	| State     | Description                               |
24	| --------- | ----------------------------------------- |
25	| `Idle`    | The tree does not have keyboard focus.    |
26	| `Focused` | The tree has keyboard focus on some node. |
27	
28	### 1.2 Events
29	
30	| Event                   | Payload | Description                                                  |
31	| ----------------------- | ------- | ------------------------------------------------------------ |
32	| `ExpandNode(String)`    | node ID | Expand a branch node.                                        |
33	| `CollapseNode(String)`  | node ID | Collapse a branch node.                                      |
34	| `ToggleNode(String)`    | node ID | Toggle expand/collapse of a branch.                          |
35	| `SelectNode(String)`    | node ID | Add a node to the selection.                                 |
36	| `DeselectNode(String)`  | node ID | Remove a node from the selection.                            |
37	| `FocusNode(String)`     | node ID | Move focus indicator to a node.                              |
38	| `FocusNext`             | —       | Move focus to the next visible node.                         |
39	| `FocusPrev`             | —       | Move focus to the previous visible node.                     |
40	| `FocusFirst`            | —       | Move focus to the first visible node.                        |
41	| `FocusLast`             | —       | Move focus to the last visible node.                         |
42	| `FocusParent`           | —       | Move focus to the parent of the focused node.                |
43	| `Focus { is_keyboard }` | `bool`  | The tree container received focus.                           |
44	| `Blur`                  | —       | The tree container lost focus.                               |
45	| `TypeaheadSearch(char)` | `char`  | Jump to the next node whose label starts with the character. |
46	
47	### 1.3 Context
48	
49	```rust
50	use ars_core::Bindable;
51	use ars_collections::{
52	    selection,
53	    Key, TreeCollection, TreeItemConfig, Collection,
54	};
55	use alloc::collections::BTreeSet;
56	
57	/// Value type for TreeView collection items.
58	#[derive(Clone, Debug, PartialEq)]
59	pub struct TreeItem {
60	    /// Display label for the node (used in typeahead and accessibility).
61	    pub label: String,
62	    /// Whether this node is disabled (not selectable, skipped during navigation).
63	    pub disabled: bool,
64	    /// When true, the node renders an expand affordance even if no children are
65	    /// present in the collection yet. Essential for lazy-loaded trees where the
66	    /// child count is unknown until the node is first expanded.
67	    pub has_children: bool,
68	    /// Optional navigation URL. When `Some`, the node renders as an `<a>` element
69	    /// instead of the default element, enabling native link behavior (middle-click
70	    /// to open in new tab, etc.). The `role="treeitem"` is preserved on the `<a>`.
71	    pub href: Option<String>,
72	}
73	
74	/// Context for the `TreeView` component.
75	#[derive(Clone, Debug, PartialEq)]
76	pub struct Context {
77	    /// The tree collection — holds all nodes, parent-child relationships,
78	    /// and visible-key computation. See `06-collections.md §2.3`.
79	    pub items: TreeCollection<TreeItem>,
80	    /// Currently selected node IDs (uses canonical `selection::Set` from `ars_collections`).
81	    pub selected: Bindable<selection::Set>,
82	    /// Full selection state machine (mode, behavior, anchor, focus, disabled keys).
83	    pub selection_state: selection::State,
84	    /// Currently expanded branch node IDs (expansion ≠ selection).
85	    /// Uses `Bindable` for controlled/uncontrolled pattern.
86	    pub expanded: Bindable<BTreeSet<Key>>,
87	    /// The node ID that holds the focus indicator.
88	    pub focused_node: Option<Key>,
89	    /// True when focus arrived via keyboard.
90	    pub focus_visible: bool,
91	    /// Allow multiple nodes to be selected simultaneously.
92	    pub multiple: bool,
93	    /// Controls which nodes can be selected (canonical `ars_collections::selection::Mode`).
94	    pub selection_mode: selection::Mode,
95	    /// Typeahead buffer (for multi-character typeahead, cleared after timeout).
96	    pub typeahead_buffer: String,
97	    /// Resolved locale for i18n.
98	    pub locale: Locale,
99	    /// Resolved translatable messages.
100	    pub messages: Messages,
101	    /// Generated element IDs for all parts.
102	    pub ids: ComponentIds,
103	}
104	
105	// NOTE: The local selection::Mode enum has been removed. TreeView now uses the
106	// canonical `ars_collections::selection::Mode` (None/Single/Multiple).
107	```
108	
109	### 1.4 Props
110	
111	```rust
112	/// Props for the `TreeView` component.
113	#[derive(Clone, Debug, PartialEq, HasId)]
114	pub struct Props {
115	    /// Unique component identifier.
116	    pub id: String,
117	    /// The tree data source. Must be a `TreeCollection<TreeItem>` from `ars_collections`.
118	    /// Built via `TreeCollection::new(roots)` where `roots: Vec<TreeItemConfig<TreeItem>>`.
119	    pub items: TreeCollection<TreeItem>,
120	    /// Controlled selected node IDs (uses canonical `selection::Set` from `ars_collections`).
121	    pub selected: Option<selection::Set>,
122	    /// Uncontrolled initial selection.
123	    pub default_selected: selection::Set,
124	    /// Controlled expanded node IDs. `Some` = controlled, `None` = uncontrolled.
125	    pub expanded: Option<BTreeSet<Key>>,
126	    /// Default expanded node IDs when uncontrolled.
127	    pub default_expanded: BTreeSet<Key>,
128	    /// Allow multiple selection.
129	    pub multiple: bool,
130	    /// Selection mode (canonical `ars_collections::selection::Mode`).
131	    pub selection_mode: selection::Mode,
132	    /// Selection behavior: Toggle (checkbox-like) or Replace (file-explorer-like).
133	    pub selection_behavior: selection::Behavior,
134	}
135	
136	impl Default for Props {
137	    fn default() -> Self {
138	        Self {
139	            id: String::new(),
140	            items: TreeCollection::new(vec![]),
141	            selected: None,
142	            default_selected: selection::Set::default(),
143	            expanded: None,
144	            default_expanded: BTreeSet::new(),
145	            multiple: false,
146	            selection_mode: selection::Mode::Single,
147	            selection_behavior: selection::Behavior::Toggle,
148	        }
149	    }
150	}
151	```
152	
153	### 1.5 Full Machine Implementation
154	
155	```rust
156	use ars_core::{TransitionPlan, PendingEffect, Bindable, AttrMap};
157	
158	/// States for the `TreeView` component.
159	#[derive(Clone, Copy, Debug, PartialEq)]
160	pub enum State {
161	    /// The tree view is in the idle state.
162	    Idle,
163	    /// The tree view is in the focused state.
164	    Focused,
165	}
166	
167	/// Events for the `TreeView` component.
168	#[derive(Clone, Debug, PartialEq)]
169	pub enum Event {
170	    /// Expand a node.
171	    ExpandNode(String),
172	    /// Collapse a node.
173	    CollapseNode(String),
174	    /// Toggle the expand/collapse state of a node.
175	    ToggleNode(String),
176	    /// Select a node.
177	    SelectNode(String),
178	    /// Deselect a node.
179	    DeselectNode(String),
180	    /// Focus a node.
181	    FocusNode(String),
182	    /// Move focus to the next node.
183	    FocusNext,
184	    /// Move focus to the previous node.
185	    FocusPrev,
186	    /// Move focus to the first node.
187	    FocusFirst,
188	    /// Move focus to the last node.
189	    FocusLast,
190	    /// Move focus to the parent of the focused node.
191	    FocusParent,
192	    /// Focus the tree view.
193	    Focus {
194	        /// Whether the focus was initiated by a keyboard.
195	        is_keyboard: bool,
196	    },
197	    /// Blur the tree view.
198	    Blur,
199	    /// Typeahead search for a node.
200	    TypeaheadSearch(char),
201	    /// Expand all nodes in the tree.
202	    ExpandAll,
203	    /// Collapse all nodes in the tree.
204	    CollapseAll,
205	}
206	
207	/// Machine for the `TreeView` component.
208	pub struct Machine;
209	
210	impl ars_core::Machine for Machine {
211	    type State   = State;
212	    type Event   = Event;
213	    type Context = Context;
214	    type Props   = Props;
215	    type Api<'a> = Api<'a>;
216	    type Messages = Messages;
217	
218	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
219	        let selected = match &props.selected {
220	            Some(v) => Bindable::controlled(v.clone()),
221	            None    => Bindable::uncontrolled(props.default_selected.clone()),
222	        };
223	        let expanded = match &props.expanded {
224	            Some(v) => Bindable::controlled(v.clone()),
225	            None    => Bindable::uncontrolled(props.default_expanded.clone()),
226	        };
227	        let selection_state = selection::State::new(
228	            props.selection_mode,
229	            props.selection_behavior,
230	        );
231	        let locale = env.locale.clone();
232	        let messages = messages.clone();
233	        let ids = ComponentIds::from_id(&props.id);
234	        (State::Idle, Context {
235	            items: props.items.clone(),
236	            selected,
237	            selection_state,
238	            expanded,
239	            focused_node: None,
240	            focus_visible: false,
241	            multiple: props.multiple,
242	            selection_mode: props.selection_mode,
243	            typeahead_buffer: String::new(),
244	            locale,
245	            messages,
246	            ids,
247	        })
248	    }
249	
250	    fn transition(
251	        state: &Self::State,
252	        event: &Self::Event,
253	        ctx: &Self::Context,
254	        _props: &Self::Props,
255	    ) -> Option<TransitionPlan<Self>> {
256	        match event {
257	
258	            Event::ExpandNode(id) => {
259	                let id = id.clone();
260	                Some(TransitionPlan::context_only(move |ctx| {
261	                    let mut exp = ctx.expanded.get().clone();
262	                    exp.insert(id);
263	                    ctx.expanded.set(exp);
264	                }))
265	            }
266	
267	            Event::CollapseNode(id) => {
268	                let id = id.clone();
269	                Some(TransitionPlan::context_only(move |ctx| {
270	                    let mut exp = ctx.expanded.get().clone();
271	                    exp.remove(&id);
272	                    ctx.expanded.set(exp);
273	                }))
274	            }
275	
276	            Event::ToggleNode(id) => {
277	                let is_expanded = ctx.expanded.get().contains(id.as_str());
278	                let id = id.clone();
279	                Some(TransitionPlan::context_only(move |ctx| {
280	                    let mut exp = ctx.expanded.get().clone();
281	                    if is_expanded {
282	                        exp.remove(&id);
283	                    } else {
284	                        exp.insert(id);
285	                    }
286	                    ctx.expanded.set(exp);
287	                }))
288	            }
289	
290	            Event::SelectNode(id) => {
291	                if ctx.selection_mode == selection::Mode::None { return None; }
292	                let key = Key::from(id);
293	                Some(TransitionPlan::context_only(move |ctx| {
294	                    let new_state = ctx.selection_state.select(key);
295	                    ctx.selected.set(new_state.selected_keys.clone());
296	                    ctx.selection_state = new_state;
297	                }))
298	            }
299	
300	            Event::DeselectNode(id) => {
301	                let key = Key::from(id);
302	                Some(TransitionPlan::context_only(move |ctx| {
303	                    let new_state = ctx.selection_state.deselect(key);
304	                    ctx.selected.set(new_state.selected_keys.clone());
305	                    ctx.selection_state = new_state;
306	                }))
307	            }
308	
309	            Event::FocusNode(id) => {
310	                let id = id.clone();
311	                Some(TransitionPlan::to(State::Focused)
312	                    .apply(move |ctx| {
313	                        ctx.focused_node = Some(id);
314	                    }))
315	            }
316	
317	            Event::Focus { is_keyboard } => {
318	                let is_keyboard = *is_keyboard;
319	                Some(TransitionPlan::to(State::Focused)
320	                    .apply(move |ctx| {
321	                        ctx.focus_visible = is_keyboard;
322	                    }))
323	            }
324	
325	            Event::Blur => {
326	                Some(TransitionPlan::to(State::Idle)
327	                    .apply(|ctx| {
328	                        ctx.focus_visible = false;
329	                    }))
330	            }
331	
332	            // ── Navigation (via TreeCollection API) ────────────────────────
333	            Event::FocusNext => {
334	                // Use TreeCollection::key_after() which respects expanded state
335	                // and skips structural nodes. Wraps to first node.
336	                let expanded = ctx.expanded.get();
337	                let visible = ctx.items.visible_keys_with_expanded(expanded);
338	                let target = match &ctx.focused_node {
339	                    Some(current) => {
340	                        let pos = visible.iter().position(|k| k == current);
341	                        pos.and_then(|p| visible.get(p + 1).or_else(|| visible.first()))
342	                    }
343	                    None => visible.first(),
344	                };
345	                target.map(|key| {
346	                    let k = key.clone();
347	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
348	                        ctx.focused_node = Some(k);
349	                        ctx.focus_visible = true;
350	                    })
351	                })
352	            }
353	
354	            Event::FocusPrev => {
355	                let expanded = ctx.expanded.get();
356	                let visible = ctx.items.visible_keys_with_expanded(expanded);
357	                let target = match &ctx.focused_node {
358	                    Some(current) => {
359	                        let pos = visible.iter().position(|k| k == current);
360	                        pos.and_then(|p| {
361	                            if p > 0 { visible.get(p - 1) }
362	                            else { visible.last() }
363	                        })
364	                    }
365	                    None => visible.last(),
366	                };
367	                target.map(|key| {
368	                    let k = key.clone();
369	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
370	                        ctx.focused_node = Some(k);
371	                        ctx.focus_visible = true;
372	                    })
373	                })
374	            }
375	
376	            Event::FocusFirst => {
377	                let expanded = ctx.expanded.get();
378	                let visible = ctx.items.visible_keys_with_expanded(expanded);
379	                visible.first().map(|key| {
380	                    let k = key.clone();
381	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
382	                        ctx.focused_node = Some(k);
383	                        ctx.focus_visible = true;
384	                    })
385	                })
386	            }
387	
388	            Event::FocusLast => {
389	                let expanded = ctx.expanded.get();
390	                let visible = ctx.items.visible_keys_with_expanded(expanded);
391	                visible.last().map(|key| {
392	                    let k = key.clone();
393	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
394	                        ctx.focused_node = Some(k);
395	                        ctx.focus_visible = true;
396	                    })
397	                })
398	            }
399	
400	            Event::FocusParent => {
401	                // Use Node::parent_key from the TreeCollection to navigate up
402	                let target = ctx.focused_node.as_ref()
403	                    .and_then(|focused| ctx.items.get(focused))
404	                    .and_then(|node| node.parent_key.clone());
405	                target.map(|key| {
406	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
407	                        ctx.focused_node = Some(key);
408	                        ctx.focus_visible = true;
409	                    })
410	                })
411	            }
412	
413	            Event::TypeaheadSearch(ch) => {
414	                // Find the next visible node whose text_value starts with ch
415	                // (case-insensitive), starting after the focused node.
416	                let ch = ch.to_lowercase().next().unwrap_or(*ch);
417	                let expanded = ctx.expanded.get();
418	                let visible = ctx.items.visible_keys_with_expanded(expanded);
419	                let start_pos = ctx.focused_node.as_ref()
420	                    .and_then(|f| visible.iter().position(|k| k == f))
421	                    .map(|p| p + 1)
422	                    .unwrap_or(0);
423	
424	                // Search from start_pos, wrapping around
425	                let target = visible.iter()
426	                    .cycle()
427	                    .skip(start_pos)
428	                    .take(visible.len())
429	                    .find(|key| {
430	                        ctx.items.get(key)
431	                            .and_then(|node| node.text_value.chars().next())
432	                            .map(|first| first.to_lowercase().next().unwrap_or(first) == ch)
433	                            .unwrap_or(false)
434	                    });
435	
436	                target.map(|key| {
437	                    let k = key.clone();
438	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
439	                        ctx.focused_node = Some(k);
440	                        ctx.focus_visible = true;
441	                    })
442	                })
443	            }
444	
445	            // ── Expand/Collapse All ────────────────────────────────────
446	            // ExpandAll — expand every expandable node
447	            Event::ExpandAll => {
448	                let expandable = ctx.items.nodes()
449	                    .filter(|n| n.has_children)
450	                    .map(|n| n.key.to_string())
451	                    .collect::<Vec<_>>();
452	                Some(TransitionPlan::context_only(move |ctx| {
453	                    let mut exp = ctx.expanded.get().clone();
454	                    for key in expandable {
455	                        exp.insert(key);
456	                    }
457	                    ctx.expanded.set(exp);
458	                }))
459	            }
460	
461	            // CollapseAll — collapse every node
462	            Event::CollapseAll => {
463	                Some(TransitionPlan::context_only(|ctx| {
464	                    ctx.expanded.set(BTreeSet::new());
465	                }))
466	            }
467	
468	            _ => None,
469	        }
470	    }
471	
472	    fn connect<'a>(
473	        state: &'a Self::State,
474	        ctx: &'a Self::Context,
475	        props: &'a Self::Props,
476	        send: &'a dyn Fn(Self::Event),
477	    ) -> Self::Api<'a> {
478	        Api { state, ctx, props, send }
479	    }
480	}
481	```
482	
483	### 1.6 Connect / API
484	
485	```rust
486	#[derive(ComponentPart)]
487	#[scope = "tree-view"]
488	pub enum Part {
489	    Root,
