532	    /// Compute (setsize, posinset) for a node from the collection.
533	    /// Returns (sibling count at this level, 1-based position among siblings).
534	    pub fn sibling_info(&self, id: &str) -> (u32, u32) {
535	        let key = Key::from(id);
536	        let node = match self.ctx.items.get(&key) { Some(n) => n, None => return (1, 1) };
537	        let siblings: Vec<_> = match &node.parent_key {
538	            Some(parent) => self.ctx.items.children_of(parent).collect(),
539	            None => {
540	                // Root-level nodes: collect all level-0 nodes
541	                self.ctx.items.nodes()
542	                    .filter(|n| n.parent_key.is_none())
543	                    .collect()
544	            }
545	        };
546	        let setsize = siblings.len() as u32;
547	        let posinset = siblings.iter()
548	            .position(|n| n.key == key)
549	            .map(|p| p as u32 + 1)
550	            .unwrap_or(1);
551	        (setsize, posinset)
552	    }
