554	    /// Attrs for the tree root container (`role="tree"`).
555	    pub fn root_attrs(&self) -> AttrMap {
556	        let mut attrs = AttrMap::new();
557	        attrs.set(HtmlAttr::Role, "tree");
558	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
559	        attrs.set(scope_attr, scope_val);
560	        attrs.set(part_attr, part_val);
561	        if self.ctx.multiple {
562	            attrs.set(HtmlAttr::Aria(AriaAttr::MultiSelectable), "true");
563	        }
564	        if let Some(focused) = &self.ctx.focused_node {
565	            attrs.set(HtmlAttr::Aria(AriaAttr::ActiveDescendant), focused);
566	        }
567	        attrs.set(HtmlAttr::TabIndex, "0");
568	        attrs
569	    }
