581	    /// Attrs for a branch node (expandable, has children).
582	    ///
583	    /// `node_id` — unique ID. Level, setsize, posinset, and disabled state
584	    /// are derived from the `TreeCollection`.
585	    ///
586	    /// When the node's `has_children` flag is true, `aria-expanded` is always
587	    /// emitted even if the collection currently contains no children for this
588	    /// node. This is essential for lazy-loaded trees where the expand affordance
589	    /// must be present before children are fetched.
590	    pub fn branch_attrs(&self, node_id: &str) -> AttrMap {
591	        let mut attrs = AttrMap::new();
592	        let is_expanded = self.is_node_expanded(node_id);
593	        let is_selected = self.is_node_selected(node_id);
594	        let is_focused  = self.is_node_focused(node_id);
595	        let node = self.get_node(node_id);
596	        let level = node.map(|n| n.level as u32 + 1).unwrap_or(1); // 1-based
597	        let (setsize, posinset) = self.sibling_info(node_id);
598	        let disabled = node.and_then(|n| n.value.as_ref()).map(|v| v.disabled).unwrap_or(false);
599	        let has_children_flag = node.and_then(|n| n.value.as_ref()).map(|v| v.has_children).unwrap_or(false);
600	        let has_actual_children = node.map(|n| n.has_children).unwrap_or(false);
601	        attrs.set(HtmlAttr::Role, "treeitem");
602	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Branch { node_id: Default::default() }.data_attrs();
603	        attrs.set(scope_attr, scope_val);
604	        attrs.set(part_attr, part_val);
605	        // Emit aria-expanded when the node has real children OR has_children flag is set
606	        if has_actual_children || has_children_flag {
607	            attrs.set(HtmlAttr::Aria(AriaAttr::Expanded), if is_expanded { "true" } else { "false" });
608	        }
609	        attrs.set(HtmlAttr::Aria(AriaAttr::Selected), if is_selected { "true" } else { "false" });
610	        attrs.set(HtmlAttr::Aria(AriaAttr::Level),   level.to_string());
611	        attrs.set(HtmlAttr::Aria(AriaAttr::SetSize), setsize.to_string());
612	        attrs.set(HtmlAttr::Aria(AriaAttr::PosInSet),posinset.to_string());
613	        if disabled { attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true"); attrs.set_bool(HtmlAttr::Data("ars-disabled"), true); }
614	        if is_selected { attrs.set_bool(HtmlAttr::Data("ars-selected"), true); }
615	        if is_expanded { attrs.set_bool(HtmlAttr::Data("ars-expanded"), true); }
616	        if is_focused && self.ctx.focus_visible { attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true); }
617	        attrs
618	    }
