624	        let mut attrs = AttrMap::new();
625	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::BranchControl { node_id: String::new() }.data_attrs();
626	        attrs.set(scope_attr, scope_val);
627	        attrs.set(part_attr, part_val);
628	        if let Some(href) = self.get_node(node_id)
629	            .and_then(|n| n.value.as_ref())
630	            .and_then(|v| v.href.as_deref())
631	        {
632	            attrs.set(HtmlAttr::Href, href);
633	        }
634	        attrs
635	    }
