684	    /// Attrs for a leaf node (no children, no expand/collapse).
685	    /// Level, setsize, posinset, and disabled state are derived from the `TreeCollection`.
686	    ///
687	    /// When the node's `has_children` flag is true (but no actual children are
688	    /// loaded), the leaf is treated as an expandable node: `aria-expanded="false"`
689	    /// is set so screen readers announce the expand affordance. Once children
690	    /// are loaded, the node transitions from `Leaf` to `Branch` in the adapter.
691	    ///
692	    /// When the node has an `href`, sets `HtmlAttr::Href` so the adapter renders
693	    /// an `<a>` element instead of the default element. `role="treeitem"` is preserved.
694	    pub fn leaf_attrs(&self, node_id: &str) -> AttrMap {
695	        let mut attrs = AttrMap::new();
696	        let is_selected = self.is_node_selected(node_id);
697	        let is_focused  = self.is_node_focused(node_id);
698	        let node = self.get_node(node_id);
699	        let level = node.map(|n| n.level as u32 + 1).unwrap_or(1);
700	        let (setsize, posinset) = self.sibling_info(node_id);
701	        let disabled = node.and_then(|n| n.value.as_ref()).map(|v| v.disabled).unwrap_or(false);
702	        let has_children_flag = node.and_then(|n| n.value.as_ref()).map(|v| v.has_children).unwrap_or(false);
703	        attrs.set(HtmlAttr::Role, "treeitem");
704	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Leaf { node_id: Default::default() }.data_attrs();
705	        attrs.set(scope_attr, scope_val);
706	        attrs.set(part_attr, part_val);
707	        // When has_children is true but no children are loaded yet, show expand affordance
708	        if has_children_flag {
709	            let is_expanded = self.is_node_expanded(node_id);
710	            attrs.set(HtmlAttr::Aria(AriaAttr::Expanded), if is_expanded { "true" } else { "false" });
711	        }
712	        attrs.set(HtmlAttr::Aria(AriaAttr::Selected), if is_selected { "true" } else { "false" });
713	        attrs.set(HtmlAttr::Aria(AriaAttr::Level),    level.to_string());
714	        attrs.set(HtmlAttr::Aria(AriaAttr::SetSize),  setsize.to_string());
715	        attrs.set(HtmlAttr::Aria(AriaAttr::PosInSet), posinset.to_string());
716	        if disabled { attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true"); attrs.set_bool(HtmlAttr::Data("ars-disabled"), true); }
717	        if is_selected { attrs.set_bool(HtmlAttr::Data("ars-selected"), true); }
718	        if is_focused && self.ctx.focus_visible { attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true); }
719	        // When href is present, the adapter renders this as an <a> element
720	        if let Some(href) = node
721	            .and_then(|n| n.value.as_ref())
722	            .and_then(|v| v.href.as_deref())
723	        {
724	            attrs.set(HtmlAttr::Href, href);
725	        }
726	        attrs
727	    }
