892	    /// (default: "Loading…"). Rendered as visually hidden text and announced
893	    /// via `aria-live="polite"`.
894	    pub loading_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
895	}
896	
897	impl Default for Messages {
