            orientation_token(self.ctx.orientation),
        )
        .set(HtmlAttr::Dir, self.ctx.dir.as_html_attr());

    if self.ctx.disabled {
        attrs.set_bool(HtmlAttr::Data("ars-disabled"), true);
    }

    attrs
}
