        vec![Key::int(1), Key::int(2), Key::int(3), Key::int(4), Key::int(7)],
        "carrot/daikon are hidden under collapsed Vegetables"
    );

    let all = tree.all_keys().cloned().collect::<Vec<_>>();
    assert_eq!(
        all,
        vec![
            Key::int(1),
            Key::int(2),
            Key::int(3),
            Key::int(4),
            Key::int(5),
            Key::int(6),
            Key::int(7),
