767	    })
768	}
769	
770	fn value_change_plan(ctx: &Context, next: State) -> TransitionPlan<Machine> {
771	    if *ctx.checked.get() == next {
772	        return TransitionPlan::context_only(|_: &mut Context| {});
773	    }
774	
775	    if ctx.checked.is_controlled() {
