782	        .apply(move |ctx: &mut Context| {
783	            ctx.checked.set(next);
784	        })
785	        .with_effect(checked_change_effect(next))
786	}
787	
788	fn checked_change_effect(next: State) -> PendingEffect<Machine> {
789	    PendingEffect::new(
790	        Effect::CheckedChange,
791	        move |_ctx: &Context, props: &Props, _send| {
792	            if let Some(cb) = &props.on_checked_change {
