//! Unit, snapshot, and behavior tests for the `tree_view` machine.

use alloc::{collections::BTreeSet, string::ToString, vec, vec::Vec};

use ars_collections::{
    Key, TreeCollection, TreeItemConfig,
    dnd::{CollectionDropTarget, DropPosition},
    selection,
};
use ars_core::{Env, Machine as _, Service};

use super::{Context, Event, Machine, Messages, Props, TreeItem};

fn item(label: &str) -> TreeItem {
    TreeItem {
        label: label.to_string(),
        ..TreeItem::default()
    }
}

fn leaf(key: u64, label: &str) -> TreeItemConfig<TreeItem> {
    TreeItemConfig {
        key: Key::int(key),
        text_value: label.to_string(),
        value: item(label),
        children: Vec::new(),
        default_expanded: false,
    }
}

fn branch(
    key: u64,
    label: &str,
    expanded: bool,
    children: Vec<TreeItemConfig<TreeItem>>,
) -> TreeItemConfig<TreeItem> {
    TreeItemConfig {
        key: Key::int(key),
        text_value: label.to_string(),
        value: item(label),
        children,
        default_expanded: expanded,
    }
}

/// ```text
/// 1: Fruits (expanded)
///   2: Apple
///   3: Banana
/// 4: Vegetables (collapsed)
///   5: Carrot
///   6: Daikon
/// 7: Grains
/// ```
fn sample_items() -> TreeCollection<TreeItem> {
    TreeCollection::new(vec![
        branch(1, "Fruits", true, vec![leaf(2, "Apple"), leaf(3, "Banana")]),
        branch(4, "Vegetables", false, vec![leaf(5, "Carrot"), leaf(6, "Daikon")]),
        leaf(7, "Grains"),
    ])
}

fn props() -> Props {
    Props::new().id("tree").items(sample_items())
}

fn service(props: Props) -> Service<Machine> {
    Service::<Machine>::new(props, &Env::default(), &Messages::default())
}

#[test]
fn smoke_init() {
    let service = service(props());
    assert_eq!(service.context().focused_node, None);
    let _ = service;
}

// Silence unused-import warnings until the full suite lands.
#[allow(dead_code)]
fn _type_anchors(
    _ctx: &Context,
    _e: Event,
    _k: Key,
    _s: selection::Set,
    _b: BTreeSet<Key>,
    _t: CollectionDropTarget,
    _p: DropPosition,
) {
}

