    TreeCollection::new(vec![
        branch(1, "Fruits", true, vec![leaf(2, "Apple"), leaf(3, "Banana")]),
        branch(4, "Vegetables", false, vec![leaf(5, "Carrot"), leaf(6, "Daikon")]),
        leaf(7, "Grains"),
    ])
}

fn props() -> Props {
    Props::new().id("tree").items(sample_items())
}

