334	                    ctx.expanded.set(exp);
335	                }))
336	            }
337	
338	            Event::CollapseNode(id) => {
339	                let id = id.clone();
340	                Some(TransitionPlan::context_only(move |ctx| {
341	                    let mut exp = ctx.expanded.get().clone();
342	                    exp.remove(&id);
343	                    ctx.expanded.set(exp);
344	                }))
345	            }
346	
347	            Event::ToggleNode(id) => {
348	                let is_expanded = ctx.expanded.get().contains(id.as_str());
349	                let id = id.clone();
350	                Some(TransitionPlan::context_only(move |ctx| {
351	                    let mut exp = ctx.expanded.get().clone();
352	                    if is_expanded {
353	                        exp.remove(&id);
354	                    } else {
355	                        exp.insert(id);
356	                    }
357	                    ctx.expanded.set(exp);
358	                }))
359	            }
360	
361	            Event::SelectNode(id) => {
362	                if ctx.selection_mode == selection::Mode::None { return None; }
363	                let key = Key::from(id);
364	                Some(TransitionPlan::context_only(move |ctx| {
365	                    let new_state = ctx.selection_state.select(key);
366	                    ctx.selected.set(new_state.selected_keys.clone());
367	                    ctx.selection_state = new_state;
368	                }))
369	            }
370	
371	            Event::DeselectNode(id) => {
372	                let key = Key::from(id);
373	                Some(TransitionPlan::context_only(move |ctx| {
374	                    let new_state = ctx.selection_state.deselect(key);
375	                    ctx.selected.set(new_state.selected_keys.clone());
376	                    ctx.selection_state = new_state;
377	                }))
378	            }
379	
380	            Event::FocusNode(id) => {
381	                let id = id.clone();
382	                Some(TransitionPlan::to(State::Focused)
383	                    .apply(move |ctx| {
384	                        ctx.focused_node = Some(id);
385	                    }))
386	            }
387	
388	            Event::Focus { is_keyboard } => {
389	                let is_keyboard = *is_keyboard;
390	                Some(TransitionPlan::to(State::Focused)
391	                    .apply(move |ctx| {
392	                        ctx.focus_visible = is_keyboard;
393	                    }))
394	            }
395	
396	            Event::Blur => {
397	                Some(TransitionPlan::to(State::Idle)
398	                    .apply(|ctx| {
399	                        ctx.focus_visible = false;
400	                    }))
401	            }
402	
403	            // ── Navigation (via TreeCollection API) ────────────────────────
404	            Event::FocusNext => {
405	                // Use TreeCollection::key_after() which respects expanded state
406	                // and skips structural nodes. Wraps to first node.
407	                let expanded = ctx.expanded.get();
408	                let visible = ctx.items.visible_keys_with_expanded(expanded);
409	                let target = match &ctx.focused_node {
410	                    Some(current) => {
411	                        let pos = visible.iter().position(|k| k == current);
412	                        pos.and_then(|p| visible.get(p + 1).or_else(|| visible.first()))
413	                    }
414	                    None => visible.first(),
415	                };
416	                target.map(|key| {
417	                    let k = key.clone();
418	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
419	                        ctx.focused_node = Some(k);
420	                        ctx.focus_visible = true;
421	                    })
422	                })
423	            }
