429	                    Some(current) => {
430	                        let pos = visible.iter().position(|k| k == current);
431	                        pos.and_then(|p| {
432	                            if p > 0 { visible.get(p - 1) }
433	                            else { visible.last() }
434	                        })
435	                    }
436	                    None => visible.last(),
437	                };
438	                target.map(|key| {
439	                    let k = key.clone();
440	                    TransitionPlan::to(State::Focused).apply(move |ctx| {
