        api.branch_attrs(&key(1)).get(&HtmlAttr::Data("ars-focus-visible")),
        Some("true"),
        "the focused node carries focus-visible"
    );
    assert!(
        api.leaf_attrs(&key(7))
            .get(&HtmlAttr::Data("ars-focus-visible"))
            .is_none(),
        "a non-focused node never carries focus-visible"
    );
}

