1	//! Unit, snapshot, keyboard, and drag-and-drop tests for the `tree_view`
2	//! machine. Mirrors the spec's "tests to add first" plus snapshot coverage of
3	//! every anatomy part across its output-affecting state/prop/context branches.
4	
5	use alloc::{collections::BTreeSet, string::ToString, vec, vec::Vec};
6	use core::cell::RefCell;
7	use std::sync::{Arc, Mutex};
8	
9	use ars_collections::{
10	    Key, TreeCollection, TreeItemConfig,
11	    dnd::{CollectionDropTarget, DropPosition},
12	    selection,
13	};
14	use ars_core::{ConnectApi as _, Env, HtmlAttr, KeyboardKey, Service, StrongSend};
15	use ars_interactions::KeyboardEventData;
16	use insta::assert_snapshot;
17	
18	use super::{
19	    Effect, Event, Machine, Messages, Part, Props, ReorderEvent, TreeItem, snapshot_attrs,
20	};
21	
22	// ----------------------------------------------------------------------------
23	// Helpers
24	// ----------------------------------------------------------------------------
25	
26	fn key(value: u64) -> Key {
27	    Key::int(value)
28	}
29	
30	fn item(label: &str) -> TreeItem {
31	    TreeItem {
32	        label: label.to_string(),
33	        ..TreeItem::default()
34	    }
35	}
36	
37	fn leaf(key: u64, label: &str) -> TreeItemConfig<TreeItem> {
38	    TreeItemConfig {
39	        key: Key::int(key),
40	        text_value: label.to_string(),
41	        value: item(label),
42	        children: Vec::new(),
43	        default_expanded: false,
44	    }
45	}
46	
47	fn leaf_with(key: u64, label: &str, value: TreeItem) -> TreeItemConfig<TreeItem> {
48	    TreeItemConfig {
49	        key: Key::int(key),
50	        text_value: label.to_string(),
51	        value,
52	        children: Vec::new(),
53	        default_expanded: false,
54	    }
55	}
56	
57	fn branch(
58	    key: u64,
59	    label: &str,
60	    expanded: bool,
61	    children: Vec<TreeItemConfig<TreeItem>>,
62	) -> TreeItemConfig<TreeItem> {
63	    TreeItemConfig {
64	        key: Key::int(key),
65	        text_value: label.to_string(),
66	        value: item(label),
67	        children,
68	        default_expanded: expanded,
69	    }
70	}
71	
72	/// ```text
73	/// 1: Fruits (expanded)
74	///   2: Apple
75	///   3: Banana
76	/// 4: Vegetables (collapsed)
77	///   5: Carrot
78	///   6: Daikon
79	/// 7: Grains
80	/// ```
81	fn sample_items() -> TreeCollection<TreeItem> {
82	    TreeCollection::new(vec![
83	        branch(1, "Fruits", true, vec![leaf(2, "Apple"), leaf(3, "Banana")]),
84	        branch(
85	            4,
86	            "Vegetables",
87	            false,
88	            vec![leaf(5, "Carrot"), leaf(6, "Daikon")],
89	        ),
90	        leaf(7, "Grains"),
91	    ])
92	}
93	
94	fn props() -> Props {
95	    Props::new().id("tree").items(sample_items())
96	}
97	
98	fn service(props: Props) -> Service<Machine> {
99	    Service::<Machine>::new(props, &Env::default(), &Messages::default())
100	}
101	
102	fn keyboard(key: KeyboardKey) -> KeyboardEventData {
103	    KeyboardEventData {
104	        key,
105	        character: None,
106	        code: key.as_w3c_str().to_owned(),
107	        shift_key: false,
108	        ctrl_key: false,
109	        alt_key: false,
110	        meta_key: false,
111	        repeat: false,
112	        is_composing: false,
113	    }
114	}
115	
116	fn printable(ch: char) -> KeyboardEventData {
117	    KeyboardEventData {
118	        key: KeyboardKey::Unidentified,
119	        character: Some(ch),
120	        code: String::new(),
121	        shift_key: false,
122	        ctrl_key: false,
123	        alt_key: false,
124	        meta_key: false,
125	        repeat: false,
126	        is_composing: false,
127	    }
128	}
129	
130	type Recorder = RefCell<Vec<Event>>;
131	
132	fn record(recorder: &Recorder, event: Event) {
133	    recorder.borrow_mut().push(event);
134	}
135	
136	// ----------------------------------------------------------------------------
137	// Init
138	// ----------------------------------------------------------------------------
139	
140	#[test]
141	fn init_uncontrolled_uses_defaults() {
142	    let mut expanded = BTreeSet::new();
143	
144	    expanded.insert(key(1));
145	
146	    let service = service(
147	        props()
148	            .default_selected(selection::Set::Single(key(2)))
149	            .default_expanded(expanded.clone()),
150	    );
151	
152	    assert!(!service.context().selected.is_controlled());
153	    assert!(!service.context().expanded.is_controlled());
154	    assert_eq!(service.context().expanded.get(), &expanded);
155	    assert!(service.context().selected.get().contains(&key(2)));
156	    assert_eq!(service.context().focused_node, None);
157	}
158	
159	#[test]
160	fn init_controlled_uses_props() {
161	    let service = service(
162	        props()
163	            .selected(selection::Set::Single(key(3)))
164	            .expanded(BTreeSet::new()),
165	    );
166	
167	    assert!(service.context().selected.is_controlled());
168	    assert!(service.context().expanded.is_controlled());
169	}
170	
171	#[test]
172	fn init_seeds_selection_state_from_default_selection() {
173	    // Regression: the selection state machine must agree with the `selected`
174	    // binding at init, otherwise the first DeselectNode would operate on an
175	    // empty state and lose the seeded selection.
176	    let service = service(props().default_selected(selection::Set::Single(key(2))));
177	
178	    assert!(
179	        service
180	            .context()
181	            .selection_state
182	            .selected_keys
183	            .contains(&key(2))
184	    );
185	}
186	
187	// ----------------------------------------------------------------------------
188	// Controlled prop syncing (on_props_changed / set_props)
189	// ----------------------------------------------------------------------------
190	
191	#[test]
192	fn on_props_changed_emits_sync_only_on_relevant_change() {
193	    let base = props();
194	
195	    assert!(<Machine as ars_core::Machine>::on_props_changed(&base, &base).is_empty());
196	
197	    let reselected = props().selected(selection::Set::Single(key(2)));
198	
199	    assert_eq!(
200	        <Machine as ars_core::Machine>::on_props_changed(&base, &reselected),
201	        vec![Event::SyncProps]
202	    );
203	}
204	
205	#[test]
206	fn set_props_syncs_controlled_selected() {
207	    let mut service = service(props().selected(selection::Set::Single(key(2))));
208	
209	    assert!(service.connect(&|_| {}).is_node_selected(&key(2)));
210	
211	    drop(service.set_props(props().selected(selection::Set::Single(key(3)))));
212	
213	    let api = service.connect(&|_| {});
214	
215	    assert!(!api.is_node_selected(&key(2)));
216	    assert!(api.is_node_selected(&key(3)));
217	}
218	
219	#[test]
220	fn set_props_syncs_items_after_reorder() {
221	    // After a reorder the consumer re-supplies a new collection; ctx.items must
222	    // reflect it (the core never mutates items itself).
223	    let mut service = service(props());
224	
225	    assert!(service.connect(&|_| {}).get_node(&key(7)).is_some());
226	
227	    let reordered = TreeCollection::new(vec![branch(1, "Fruits", true, vec![leaf(2, "Apple")])]);
228	
229	    drop(service.set_props(props().items(reordered)));
230	
231	    let api = service.connect(&|_| {});
232	
233	    assert!(api.get_node(&key(7)).is_none(), "Grains was removed");
234	    assert!(api.get_node(&key(2)).is_some());
235	}
236	
237	// ----------------------------------------------------------------------------
238	// Expand / collapse / toggle
239	// ----------------------------------------------------------------------------
240	
241	#[test]
242	fn expand_node_adds_to_expanded() {
243	    let mut service = service(props());
244	
245	    drop(service.send(Event::ExpandNode(key(4))));
246	
247	    assert!(service.context().expanded.get().contains(&key(4)));
248	}
249	
250	#[test]
251	fn collapse_node_removes_from_expanded() {
252	    let mut service = service(props());
253	
254	    drop(service.send(Event::ExpandNode(key(4))));
255	    drop(service.send(Event::CollapseNode(key(4))));
256	
257	    assert!(!service.context().expanded.get().contains(&key(4)));
258	}
259	
260	#[test]

